#include <iostream>
#include <string>
#include <vector>
#include <cstdlib>
#include <ctime>
#include <cmath>
#include <sys/socket.h>
#include <arpa/inet.h>
#include <netinet/in.h>

using namespace std;

const int PORT = 8080;
const int MAX_CLIENTS = 10;
const int BUFFER_SIZE = 256;

struct Player {
    string name;
    double x, y, z;
};

vector<Player> players;

void handlePacket(char* buffer) {
    // Parse the packet data and update player position
    int id = atoi(buffer);
    double x = atof(buffer + 4);
    double y = atof(buffer + 8);
    double z = atof(buffer + 12);

    players[id].x = x;
    players[id].y = y;
    players[id].z = z;
}

void handleActionPacket(char* buffer) {
    // Parse the packet data and update player action
    int id = atoi(buffer);
    string action = buffer + 4;

    if (action == "shoot") {
        players[id].shoot();
    } else if (action == "jump") {
        players[id].jump();
    }
}

int main() {
    // Initialize the game server
    int sock = socket(AF_INET, SOCK_DGRAM, 0);
    struct sockaddr_in serv_addr;
    memset(&serv_addr, 0, sizeof(serv_addr));
    serv_addr.sin_family = AF_INET;
    serv_addr.sin_port = htons(PORT);
    inet_pton(AF_INET, "127.0.0.1", &serv_addr.sin_addr);

    // Bind the socket to the port
    bind(sock, (struct sockaddr*)&serv_addr, sizeof(serv_addr));

    // Initialize the players vector
    for (int i = 0; i < MAX_CLIENTS; i++) {
        Player player;
        player.name = "Player" + to_string(i);
        player.x = 0;
        player.y = 0;
        player.z = 0;
        players.push_back(player);
    }

    // Start the game loop
    while (true) {
        char buffer[BUFFER_SIZE];
        int bytesReceived = recvfrom(sock, buffer, BUFFER_SIZE, 0, NULL, NULL);

        if (bytesReceived > 0) {
            string packetType = buffer.substr(0, 4);
            if (packetType == "POS ") {
                handlePacket(buffer);
            } else if (packetType == "ACT ") {
                handleActionPacket(buffer);
            }
        }
    }

    return 0;
}